import{_ as h,C as d,o as r,c as g,a2 as t,b as i,w as e,a as o,E as n,a3 as s}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"Java 基础面试指南","description":"","frontmatter":{"title":"Java 基础面试指南","module":"java-basics","difficulty":"intermediate","interviewFrequency":"high","tags":["Java 基础","面试指南","面试高频"],"codeExample":"01-java-core/java-basics/src/main/java/com/example/basics/","relatedEntries":["/1-java-core/1.2-java-advanced/99-interview","/1-java-core/1.3-concurrent/99-interview","/1-java-core/1.4-jvm/99-interview"],"prerequisites":["/1-java-core/1.1-java-basics/01-data-types","/1-java-core/1.1-java-basics/03-string-deep-dive","/1-java-core/1.1-java-basics/04-oop","/1-java-core/1.1-java-basics/05-collections"],"estimatedTime":"60min"},"headers":[],"relativePath":"1-java-core/1.1-java-basics/99-interview.md","filePath":"1-java-core/1.1-java-basics/99-interview.md","lastUpdated":null}'),c={name:"1-java-core/1.1-java-basics/99-interview.md"};function u(p,a,E,A,B,m){const l=d("Mermaid");return r(),g("div",null,[a[2]||(a[2]=t('<h1 id="java-基础面试指南" tabindex="-1">Java 基础面试指南 <a class="header-anchor" href="#java-基础面试指南" aria-label="Permalink to &quot;Java 基础面试指南&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>本指南汇总了 Java 基础模块中所有高频面试题，按照面试出现频率排序。建议在学习完各知识点后，用本指南进行系统复习和查漏补缺。</p><blockquote><p>💡 <strong>使用建议</strong>：先快速浏览所有题目，标记不熟悉的，然后回到对应知识点深入学习。</p></blockquote><h2 id="面试题频率分布" tabindex="-1">面试题频率分布 <a class="header-anchor" href="#面试题频率分布" aria-label="Permalink to &quot;面试题频率分布&quot;">​</a></h2>',5)),(r(),i(s,null,{default:e(()=>[n(l,{id:"mermaid-17",class:"mermaid",graph:"pie%20title%20Java%20%E5%9F%BA%E7%A1%80%E9%9D%A2%E8%AF%95%E9%A2%98%E5%88%86%E5%B8%83%0A%20%20%20%20%22%E9%9B%86%E5%90%88%E6%A1%86%E6%9E%B6%22%20%3A%2030%0A%20%20%20%20%22String%20%E7%9B%B8%E5%85%B3%22%20%3A%2015%0A%20%20%20%20%22%E9%9D%A2%E5%90%91%E5%AF%B9%E8%B1%A1%22%20%3A%2015%0A%20%20%20%20%22%E6%95%B0%E6%8D%AE%E7%B1%BB%E5%9E%8B%2F%E8%A3%85%E7%AE%B1%E6%8B%86%E7%AE%B1%22%20%3A%2010%0A%20%20%20%20%22Lambda%2FStream%22%20%3A%2010%0A%20%20%20%20%22%E6%B3%9B%E5%9E%8B%2F%E5%8F%8D%E5%B0%84%2F%E6%B3%A8%E8%A7%A3%22%20%3A%2010%0A%20%20%20%20%22IO%2F%E5%BC%82%E5%B8%B8%2F%E6%96%B0%E7%89%B9%E6%80%A7%22%20%3A%2010%0A"})]),fallback:e(()=>[...a[0]||(a[0]=[o(" Loading... ",-1)])]),_:1})),a[3]||(a[3]=t('<hr><h2 id="🔥🔥🔥-高频面试题-必须掌握" tabindex="-1">🔥🔥🔥 高频面试题（必须掌握） <a class="header-anchor" href="#🔥🔥🔥-高频面试题-必须掌握" aria-label="Permalink to &quot;🔥🔥🔥 高频面试题（必须掌握）&quot;">​</a></h2><h3 id="_1-hashmap-的-put-流程是怎样的" tabindex="-1">1. HashMap 的 put 流程是怎样的？ <a class="header-anchor" href="#_1-hashmap-的-put-流程是怎样的" aria-label="Permalink to &quot;1. HashMap 的 put 流程是怎样的？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./05-collections.html">集合框架</a> | <strong>难度</strong>：⭐⭐⭐</p><p><strong>答题要点</strong>：</p><ol><li>计算 hash（扰动函数：高 16 位异或低 16 位）</li><li>通过 <code>(n-1) &amp; hash</code> 确定桶位置</li><li>桶为空直接放入；不为空则判断 key 是否相同</li><li>链表尾插法（JDK 8），链表长度 ≥ 8 且数组长度 ≥ 64 时转红黑树</li><li>插入后判断是否需要扩容（size &gt; capacity × loadFactor）</li></ol><p><strong>追问链路</strong>：</p><ul><li>为什么用尾插法？→ JDK 7 头插法多线程扩容会形成环形链表</li><li>为什么树化阈值是 8？→ 泊松分布，链表长度达到 8 的概率极低</li><li>HashMap 线程安全吗？→ 不安全，用 ConcurrentHashMap</li></ul><hr><h3 id="_2-hashmap-的扩容机制" tabindex="-1">2. HashMap 的扩容机制？ <a class="header-anchor" href="#_2-hashmap-的扩容机制" aria-label="Permalink to &quot;2. HashMap 的扩容机制？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./05-collections.html">集合框架</a> | <strong>难度</strong>：⭐⭐⭐</p><p><strong>答题要点</strong>：</p><ol><li>触发条件：size &gt; capacity × loadFactor（默认 12）</li><li>新容量 = 旧容量 × 2</li><li>JDK 8 优化：通过 <code>hash &amp; oldCap</code> 判断元素新位置（0 留原位，1 移到原位 + oldCap）</li><li>链表拆分为高低位两个子链表</li></ol><p><strong>追问链路</strong>：</p><ul><li>为什么容量必须是 2 的幂？→ <code>(n-1) &amp; hash</code> 等价于 <code>hash % n</code>，位运算更快</li><li>负载因子为什么是 0.75？→ 时间和空间的折中</li></ul><hr><h3 id="_3-arraylist-和-linkedlist-的区别" tabindex="-1">3. ArrayList 和 LinkedList 的区别？ <a class="header-anchor" href="#_3-arraylist-和-linkedlist-的区别" aria-label="Permalink to &quot;3. ArrayList 和 LinkedList 的区别？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./05-collections.html">集合框架</a> | <strong>难度</strong>：⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>ArrayList：动态数组，O(1) 随机访问，1.5 倍扩容</li><li>LinkedList：双向链表，O(1) 头尾插入，O(n) 随机访问</li><li>实际开发几乎总是选 ArrayList（CPU 缓存友好）</li></ul><hr><h3 id="_4-string-为什么是不可变的" tabindex="-1">4. String 为什么是不可变的？ <a class="header-anchor" href="#_4-string-为什么是不可变的" aria-label="Permalink to &quot;4. String 为什么是不可变的？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./03-string-deep-dive.html">String 深入</a> | <strong>难度</strong>：⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>final 类 + private final char[] + 无修改方法</li><li>好处：线程安全、常量池共享、hashCode 缓存、安全性</li></ul><p><strong>追问链路</strong>：</p><ul><li><code>new String(&quot;abc&quot;)</code> 创建几个对象？→ 1 或 2 个</li><li>JDK 9 为什么改用 byte[]？→ Compact Strings 优化</li></ul><hr><h3 id="_5-string、stringbuilder、stringbuffer-的区别" tabindex="-1">5. String、StringBuilder、StringBuffer 的区别？ <a class="header-anchor" href="#_5-string、stringbuilder、stringbuffer-的区别" aria-label="Permalink to &quot;5. String、StringBuilder、StringBuffer 的区别？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./03-string-deep-dive.html">String 深入</a> | <strong>难度</strong>：⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>String 不可变，StringBuilder 可变非线程安全，StringBuffer 可变线程安全</li><li>单线程拼接用 StringBuilder，多线程用 StringBuffer（实际很少用）</li><li>StringBuilder 默认容量 16，扩容 oldCap × 2 + 2</li></ul><hr><h3 id="_6-java-是值传递还是引用传递" tabindex="-1">6. Java 是值传递还是引用传递？ <a class="header-anchor" href="#_6-java-是值传递还是引用传递" aria-label="Permalink to &quot;6. Java 是值传递还是引用传递？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./02-value-passing.html">值传递与引用传递</a> | <strong>难度</strong>：⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>Java 只有值传递</li><li>基本类型传值的副本，引用类型传引用（地址）的副本</li><li>可以通过副本修改对象内容，但不能让原引用指向新对象</li><li>swap 函数无法实现</li></ul><hr><h3 id="_7-多态的实现原理" tabindex="-1">7. 多态的实现原理？ <a class="header-anchor" href="#_7-多态的实现原理" aria-label="Permalink to &quot;7. 多态的实现原理？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./04-oop.html">面向对象</a> | <strong>难度</strong>：⭐⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>通过虚方法表（vtable）实现</li><li>每个类加载时创建 vtable，子类继承并覆盖父类的方法入口</li><li>运行时通过对象头的类型指针找到实际类的 vtable</li></ul><p><strong>追问链路</strong>：</p><ul><li>static/final/private 方法能多态吗？→ 不能，静态绑定</li><li>构造方法中调用虚方法？→ 危险，子类可能未初始化</li></ul><hr><h3 id="_8-重写-equals-为什么必须重写-hashcode" tabindex="-1">8. 重写 equals 为什么必须重写 hashCode？ <a class="header-anchor" href="#_8-重写-equals-为什么必须重写-hashcode" aria-label="Permalink to &quot;8. 重写 equals 为什么必须重写 hashCode？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./04-oop.html">面向对象</a> | <strong>难度</strong>：⭐⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>契约：equals 相等 → hashCode 必须相等</li><li>不重写会导致 HashMap/HashSet 行为异常</li><li>用 <code>Objects.hash()</code> 重写</li></ul><hr><h3 id="_9-抽象类和接口的区别" tabindex="-1">9. 抽象类和接口的区别？ <a class="header-anchor" href="#_9-抽象类和接口的区别" aria-label="Permalink to &quot;9. 抽象类和接口的区别？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./04-oop.html">面向对象</a> | <strong>难度</strong>：⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>抽象类：有构造方法、任意成员、单继承、is-a 关系</li><li>接口：默认 public static final 变量、JDK 8+ default 方法、多实现、has-a 能力</li><li>需要共享代码用抽象类，定义行为契约用接口</li></ul><hr><h3 id="_10-integer-缓存池的范围" tabindex="-1">10. Integer 缓存池的范围？ <a class="header-anchor" href="#_10-integer-缓存池的范围" aria-label="Permalink to &quot;10. Integer 缓存池的范围？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./01-data-types.html">数据类型</a> | <strong>难度</strong>：⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>默认 -128 ~ 127，可通过 <code>-XX:AutoBoxCacheMax</code> 调整上限</li><li><code>Integer.valueOf()</code> 走缓存，<code>new Integer()</code> 不走</li><li>Float/Double 没有缓存</li></ul><hr><h3 id="_11-自动装箱和拆箱的原理和陷阱" tabindex="-1">11. 自动装箱和拆箱的原理和陷阱？ <a class="header-anchor" href="#_11-自动装箱和拆箱的原理和陷阱" aria-label="Permalink to &quot;11. 自动装箱和拆箱的原理和陷阱？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./01-data-types.html">数据类型</a> | <strong>难度</strong>：⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>装箱调用 <code>valueOf()</code>，拆箱调用 <code>xxxValue()</code></li><li>陷阱：null 拆箱 NPE、循环中频繁装箱、三目运算符隐式拆箱</li></ul><hr><h3 id="_12-stream-的中间操作和终端操作的区别" tabindex="-1">12. Stream 的中间操作和终端操作的区别？ <a class="header-anchor" href="#_12-stream-的中间操作和终端操作的区别" aria-label="Permalink to &quot;12. Stream 的中间操作和终端操作的区别？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./11-lambda-stream.html">Lambda 与 Stream</a> | <strong>难度</strong>：⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>中间操作返回 Stream，惰性求值（filter/map/sorted）</li><li>终端操作触发执行，返回结果（collect/forEach/reduce）</li><li>Stream 只能消费一次</li></ul><hr><h3 id="_13-泛型的类型擦除是什么" tabindex="-1">13. 泛型的类型擦除是什么？ <a class="header-anchor" href="#_13-泛型的类型擦除是什么" aria-label="Permalink to &quot;13. 泛型的类型擦除是什么？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./07-generics.html">泛型</a> | <strong>难度</strong>：⭐⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>编译后泛型信息被移除，无界擦除为 Object，有上界擦除为上界类型</li><li>影响：运行时无法获取泛型类型、不能创建泛型数组、不能用基本类型</li><li>绕过：TypeReference/TypeToken（匿名子类 + 反射）</li></ul><hr><h2 id="🔥🔥-中频面试题-应该掌握" tabindex="-1">🔥🔥 中频面试题（应该掌握） <a class="header-anchor" href="#🔥🔥-中频面试题-应该掌握" aria-label="Permalink to &quot;🔥🔥 中频面试题（应该掌握）&quot;">​</a></h2><h3 id="_14-checked-和-unchecked-异常的区别" tabindex="-1">14. Checked 和 Unchecked 异常的区别？ <a class="header-anchor" href="#_14-checked-和-unchecked-异常的区别" aria-label="Permalink to &quot;14. Checked 和 Unchecked 异常的区别？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./06-exceptions.html">异常处理</a> | <strong>难度</strong>：⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>Checked：编译器强制处理，IOException/SQLException</li><li>Unchecked：RuntimeException 子类，NullPointerException/ClassCastException</li><li>自定义业务异常通常继承 RuntimeException</li></ul><hr><h3 id="_15-extends-t-和-super-t-的区别" tabindex="-1">15. <code>&lt;? extends T&gt;</code> 和 <code>&lt;? super T&gt;</code> 的区别？ <a class="header-anchor" href="#_15-extends-t-和-super-t-的区别" aria-label="Permalink to &quot;15. `&lt;? extends T&gt;` 和 `&lt;? super T&gt;` 的区别？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./07-generics.html">泛型</a> | <strong>难度</strong>：⭐⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>extends：上界，只能读（Producer）</li><li>super：下界，可以写（Consumer）</li><li>PECS 原则：Producer Extends, Consumer Super</li></ul><hr><h3 id="_16-反射的原理和性能优化" tabindex="-1">16. 反射的原理和性能优化？ <a class="header-anchor" href="#_16-反射的原理和性能优化" aria-label="Permalink to &quot;16. 反射的原理和性能优化？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./08-reflection.html">反射</a> | <strong>难度</strong>：⭐⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>三种获取 Class 的方式：.class / getClass() / Class.forName()</li><li>性能优化：缓存 Method/Field、setAccessible(true)、MethodHandle</li><li>框架应用：Spring IoC、MyBatis、Jackson</li></ul><hr><h3 id="_17-bio、nio、aio-的区别" tabindex="-1">17. BIO、NIO、AIO 的区别？ <a class="header-anchor" href="#_17-bio、nio、aio-的区别" aria-label="Permalink to &quot;17. BIO、NIO、AIO 的区别？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./10-io-streams.html">IO 流</a> | <strong>难度</strong>：⭐⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>BIO：同步阻塞，一连接一线程</li><li>NIO：同步非阻塞，Channel/Buffer/Selector 多路复用</li><li>AIO：异步非阻塞，回调机制</li><li>Netty 基于 NIO</li></ul><hr><h3 id="_18-并行流什么时候用-注意事项" tabindex="-1">18. 并行流什么时候用？注意事项？ <a class="header-anchor" href="#_18-并行流什么时候用-注意事项" aria-label="Permalink to &quot;18. 并行流什么时候用？注意事项？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./11-lambda-stream.html">Lambda 与 Stream</a> | <strong>难度</strong>：⭐⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>适用：数据量大、计算密集、无共享状态</li><li>注意：不要修改共享变量、forEach 不保证顺序、数据源要支持高效分割</li><li>默认使用 ForkJoinPool.commonPool()</li></ul><hr><h3 id="_19-jdk-8-有哪些重要新特性" tabindex="-1">19. JDK 8 有哪些重要新特性？ <a class="header-anchor" href="#_19-jdk-8-有哪些重要新特性" aria-label="Permalink to &quot;19. JDK 8 有哪些重要新特性？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./12-new-features.html">JDK 新特性</a> | <strong>难度</strong>：⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>Lambda + Stream + Optional + Date-Time API + 接口默认方法</li></ul><hr><h3 id="_20-虚拟线程和平台线程的区别" tabindex="-1">20. 虚拟线程和平台线程的区别？ <a class="header-anchor" href="#_20-虚拟线程和平台线程的区别" aria-label="Permalink to &quot;20. 虚拟线程和平台线程的区别？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./12-new-features.html">JDK 新特性</a> | <strong>难度</strong>：⭐⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>虚拟线程：JVM 管理，极低创建成本，百万级，适合 IO 密集型</li><li>平台线程：OS 线程包装，~1MB 栈内存，通常几千个</li><li>虚拟线程不需要池化</li></ul><hr><h3 id="_21-try-with-resources-的原理" tabindex="-1">21. try-with-resources 的原理？ <a class="header-anchor" href="#_21-try-with-resources-的原理" aria-label="Permalink to &quot;21. try-with-resources 的原理？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./06-exceptions.html">异常处理</a> | <strong>难度</strong>：⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>编译器语法糖，自动在 finally 中调用 close()</li><li>资源需实现 AutoCloseable</li><li>close() 异常作为 suppressed exception</li></ul><hr><h3 id="_22-注解的原理-retention-的三个级别" tabindex="-1">22. 注解的原理？@Retention 的三个级别？ <a class="header-anchor" href="#_22-注解的原理-retention-的三个级别" aria-label="Permalink to &quot;22. 注解的原理？@Retention 的三个级别？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./09-annotations.html">注解</a> | <strong>难度</strong>：⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>注解本质是接口，运行时通过反射读取</li><li>SOURCE（编译后丢弃）、CLASS（.class 文件中）、RUNTIME（运行时可读）</li><li>Spring 注解都是 RUNTIME 级别</li></ul><hr><h3 id="_23-concurrentmodificationexception-是什么-如何避免" tabindex="-1">23. ConcurrentModificationException 是什么？如何避免？ <a class="header-anchor" href="#_23-concurrentmodificationexception-是什么-如何避免" aria-label="Permalink to &quot;23. ConcurrentModificationException 是什么？如何避免？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./05-collections.html">集合框架</a> | <strong>难度</strong>：⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>增强 for 循环中修改集合触发 fail-fast 机制</li><li>解决：Iterator.remove()、removeIf()、CopyOnWriteArrayList</li></ul><hr><h3 id="_24-linkedhashmap-如何实现-lru-缓存" tabindex="-1">24. LinkedHashMap 如何实现 LRU 缓存？ <a class="header-anchor" href="#_24-linkedhashmap-如何实现-lru-缓存" aria-label="Permalink to &quot;24. LinkedHashMap 如何实现 LRU 缓存？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./05-collections.html">集合框架</a> | <strong>难度</strong>：⭐⭐⭐</p><p><strong>答题要点</strong>：</p><ul><li>构造时 accessOrder=true，按访问顺序排列</li><li>重写 removeEldestEntry()，超过容量时移除最久未访问的元素</li></ul><hr><h2 id="🔥-低频面试题-了解即可" tabindex="-1">🔥 低频面试题（了解即可） <a class="header-anchor" href="#🔥-低频面试题-了解即可" aria-label="Permalink to &quot;🔥 低频面试题（了解即可）&quot;">​</a></h2><h3 id="_25-record-和普通类的区别" tabindex="-1">25. Record 和普通类的区别？ <a class="header-anchor" href="#_25-record-和普通类的区别" aria-label="Permalink to &quot;25. Record 和普通类的区别？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./12-new-features.html">JDK 新特性</a> | <strong>难度</strong>：⭐⭐</p><ul><li>不可变数据载体，自动生成构造方法/getter/equals/hashCode/toString</li><li>final 类，字段 final，不能声明实例字段</li></ul><h3 id="_26-sealed-classes-的作用" tabindex="-1">26. Sealed Classes 的作用？ <a class="header-anchor" href="#_26-sealed-classes-的作用" aria-label="Permalink to &quot;26. Sealed Classes 的作用？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./12-new-features.html">JDK 新特性</a> | <strong>难度</strong>：⭐⭐</p><ul><li>限制哪些类可以继承/实现</li><li>permits 子句指定允许的子类</li></ul><h3 id="_27-内部类有几种-静态内部类和成员内部类的区别" tabindex="-1">27. 内部类有几种？静态内部类和成员内部类的区别？ <a class="header-anchor" href="#_27-内部类有几种-静态内部类和成员内部类的区别" aria-label="Permalink to &quot;27. 内部类有几种？静态内部类和成员内部类的区别？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./04-oop.html">面向对象</a> | <strong>难度</strong>：⭐⭐</p><ul><li>四种：成员内部类、静态内部类、局部内部类、匿名内部类</li><li>静态内部类不持有外部类引用，优先使用</li></ul><h3 id="_28-mappedbytebuffer-是什么-什么时候用" tabindex="-1">28. MappedByteBuffer 是什么？什么时候用？ <a class="header-anchor" href="#_28-mappedbytebuffer-是什么-什么时候用" aria-label="Permalink to &quot;28. MappedByteBuffer 是什么？什么时候用？&quot;">​</a></h3><p><strong>来源</strong>：<a href="./10-io-streams.html">IO 流</a> | <strong>难度</strong>：⭐⭐</p><ul><li>内存映射文件，将文件映射到虚拟内存</li><li>适合超大文件随机访问，零拷贝</li></ul><hr><h2 id="面试知识图谱" tabindex="-1">面试知识图谱 <a class="header-anchor" href="#面试知识图谱" aria-label="Permalink to &quot;面试知识图谱&quot;">​</a></h2>',146)),(r(),i(s,null,{default:e(()=>[n(l,{id:"mermaid-812",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20subgraph%20%22%E6%95%B0%E6%8D%AE%E7%B1%BB%E5%9E%8B%22%0A%20%20%20%20%20%20%20%20A1%5B%E5%9F%BA%E6%9C%AC%E7%B1%BB%E5%9E%8B%20vs%20%E5%8C%85%E8%A3%85%E7%B1%BB%5D%20--%3E%20A2%5B%E8%A3%85%E7%AE%B1%E6%8B%86%E7%AE%B1%5D%0A%20%20%20%20%20%20%20%20A2%20--%3E%20A3%5B%E7%BC%93%E5%AD%98%E6%B1%A0%5D%0A%20%20%20%20%20%20%20%20A1%20--%3E%20A4%5B%E5%80%BC%E4%BC%A0%E9%80%92%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22String%22%0A%20%20%20%20%20%20%20%20B1%5B%E4%B8%8D%E5%8F%AF%E5%8F%98%E6%80%A7%5D%20--%3E%20B2%5B%E5%B8%B8%E9%87%8F%E6%B1%A0%5D%0A%20%20%20%20%20%20%20%20B2%20--%3E%20B3%5Bintern%5D%0A%20%20%20%20%20%20%20%20B1%20--%3E%20B4%5BStringBuilder%2FBuffer%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22%E9%9D%A2%E5%90%91%E5%AF%B9%E8%B1%A1%22%0A%20%20%20%20%20%20%20%20C1%5B%E5%B0%81%E8%A3%85%5D%20--%3E%20C2%5B%E7%BB%A7%E6%89%BF%2F%E9%87%8D%E5%86%99%5D%0A%20%20%20%20%20%20%20%20C2%20--%3E%20C3%5B%E5%A4%9A%E6%80%81%2Fvtable%5D%0A%20%20%20%20%20%20%20%20C3%20--%3E%20C4%5B%E6%8A%BD%E8%B1%A1%E7%B1%BB%20vs%20%E6%8E%A5%E5%8F%A3%5D%0A%20%20%20%20%20%20%20%20C1%20--%3E%20C5%5Bequals%2FhashCode%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22%E9%9B%86%E5%90%88%E6%A1%86%E6%9E%B6%22%0A%20%20%20%20%20%20%20%20D1%5BArrayList%20%E6%89%A9%E5%AE%B9%5D%20--%3E%20D2%5BHashMap%20put%20%E6%B5%81%E7%A8%8B%5D%0A%20%20%20%20%20%20%20%20D2%20--%3E%20D3%5BHashMap%20%E6%89%A9%E5%AE%B9%2F%E7%BA%A2%E9%BB%91%E6%A0%91%5D%0A%20%20%20%20%20%20%20%20D3%20--%3E%20D4%5BConcurrentHashMap%5D%0A%20%20%20%20%20%20%20%20D1%20--%3E%20D5%5B%E9%81%8D%E5%8E%86%E5%88%A0%E9%99%A4%E9%99%B7%E9%98%B1%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22%E9%AB%98%E7%BA%A7%E7%89%B9%E6%80%A7%22%0A%20%20%20%20%20%20%20%20E1%5B%E6%B3%9B%E5%9E%8B%2F%E7%B1%BB%E5%9E%8B%E6%93%A6%E9%99%A4%5D%20--%3E%20E2%5B%E5%8F%8D%E5%B0%84%5D%0A%20%20%20%20%20%20%20%20E2%20--%3E%20E3%5B%E6%B3%A8%E8%A7%A3%5D%0A%20%20%20%20%20%20%20%20E3%20--%3E%20E4%5BSpring%20%E6%A1%86%E6%9E%B6%E5%8E%9F%E7%90%86%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%22%E7%8E%B0%E4%BB%A3%20Java%22%0A%20%20%20%20%20%20%20%20F1%5BLambda%2FStream%5D%20--%3E%20F2%5BOptional%5D%0A%20%20%20%20%20%20%20%20F2%20--%3E%20F3%5BJDK%2017%20%E7%89%B9%E6%80%A7%5D%0A%20%20%20%20%20%20%20%20F3%20--%3E%20F4%5B%E8%99%9A%E6%8B%9F%E7%BA%BF%E7%A8%8B%5D%0A%20%20%20%20end%0A%0A%20%20%20%20A3%20--%3E%20D2%0A%20%20%20%20C5%20--%3E%20D2%0A%20%20%20%20E2%20--%3E%20E4%0A%20%20%20%20F1%20--%3E%20D1%0A"})]),fallback:e(()=>[...a[1]||(a[1]=[o(" Loading... ",-1)])]),_:1})),a[4]||(a[4]=t('<h2 id="面试技巧" tabindex="-1">面试技巧 <a class="header-anchor" href="#面试技巧" aria-label="Permalink to &quot;面试技巧&quot;">​</a></h2><ol><li><strong>HashMap 是必考题</strong>：put 流程、扩容机制、红黑树转换条件，必须烂熟于心</li><li><strong>String 三连问</strong>：不可变性 → 常量池 → StringBuilder 区别，准备好追问链路</li><li><strong>值传递</strong>：用 swap 例子一锤定音，Java 只有值传递</li><li><strong>源码级回答</strong>：提到关键源码（如 <code>Integer.valueOf()</code>、<code>HashMap.putVal()</code>）会加分</li><li><strong>对比回答</strong>：ArrayList vs LinkedList、Checked vs Unchecked、抽象类 vs 接口，用表格思维组织答案</li><li><strong>新特性加分</strong>：提到 JDK 17/21 的新特性（Record、虚拟线程）展示技术敏感度</li></ol><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://javaguide.cn/" target="_blank" rel="noreferrer">Java 面试指南 - JavaGuide</a></li><li><a href="https://www.oreilly.com/library/view/effective-java/9780134686097/" target="_blank" rel="noreferrer">Effective Java（第三版）</a></li><li><a href="https://time.geekbang.org/column/intro/82" target="_blank" rel="noreferrer">Java 核心技术面试精讲</a></li></ul>',4))])}const _=h(c,[["render",u]]);export{b as __pageData,_ as default};
